const sleep=ms=>new Promise(resolve=>setTimeout(resolve,ms));export class AdsManager{constructor(isProduction=false){this.isProduction=isProduction;this.adUnitIds={banner:"ca-app-pub-xxxxxxxxxxxxxxxx/xxxxxxxxxx",interstitial:"ca-app-pub-xxxxxxxxxxxxxxxx/xxxxxxxxxx",rewarded:"ca-app-pub-xxxxxxxxxxxxxxxx/xxxxxxxxxx"}}async showInterstitialAd(){if(!this.isProduction){console.log("[ADS] Interstitial ad would show here");await sleep(400);return true}try{return true}catch(e){console.error("Ad error:",e);return false}}async showRewardedAd(rewardType="revive"){if(!this.isProduction){const adLabel=this.getAdUnitId(rewardType);console.log(`[ADS] Rewarded ad (${rewardType}) would show here -> ${adLabel}`);await new Promise(resolve=>setTimeout(resolve,500));return true}try{return true}catch(e){console.error("Rewarded ad error:",e);return false}}getAdUnitId(reason="rewarded"){return{revive:this.adUnitIds.rewarded,"double-reward":this.adUnitIds.rewarded,"daily-bonus":this.adUnitIds.rewarded,interstitial:this.adUnitIds.interstitial,banner:this.adUnitIds.banner,rewarded:this.adUnitIds.rewarded}[reason]||this.adUnitIds.rewarded}async showBannerAd(){if(!this.isProduction){let banner=document.getElementById("ad-banner");if(!banner){banner=document.createElement("div");banner.id="ad-banner";banner.className="ad-banner";banner.innerHTML=`<span>📣 Mock Ad — Monetización activa (dev mode)</span>`;document.body.appendChild(banner)}banner.classList.add("visible");console.log("[ADS] Banner ad mock visible");return true}try{return true}catch(e){console.error("Banner ad error:",e);return false}}async hideBannerAd(){try{const banner=document.getElementById("ad-banner");if(banner){banner.classList.remove("visible")}}catch(e){console.error("Hide banner error:",e)}}async isAdReady(){return this.isProduction}}export function shouldShowInterstitial(battleCount=0){return battleCount>0&&battleCount%3===0}export async function offerReviveWithAd(adsManager){const userAccepts=confirm("Ver anuncio para revivir con 30% salud?");if(userAccepts){const watched=await adsManager.showRewardedAd("revive");if(watched){return.3}}return 0}export async function offerDoubleRewardWithAd(adsManager,score){const userAccepts=confirm("Ver anuncio para duplicar recompensa?");if(userAccepts){const watched=await adsManager.showRewardedAd("double-reward");if(watched){return score*2}}return score}export async function claimDailyBonusWithAd(adsManager){const lastClaim=localStorage.getItem("DAILY_AD_CLAIM")||"0";const now=Date.now();const dayMs=24*60*60*1e3;if(now-parseInt(lastClaim)<dayMs){return{claimed:false,message:"Ya reclamaste tu bonus hoy"}}const watched=await adsManager.showRewardedAd("daily-bonus");if(watched){localStorage.setItem("DAILY_AD_CLAIM",String(now));return{claimed:true,bonus:{gold:100,xp:50}}}return{claimed:false,message:"Anuncio cancelado"}}